import React from 'react';

const Locations: React.FC = () => {
  return (
    <div>
      <h1>Gestión de Ubicaciones</h1>
      <div className="card">
        <p>Módulo de ubicaciones en desarrollo...</p>
        <p>Funcionalidades incluidas:</p>
        <ul>
          <li>Gestión de granjas, galpones y corrales</li>
          <li>Control de capacidad</li>
          <li>Movimientos de animales</li>
          <li>Ocupación en tiempo real</li>
        </ul>
      </div>
    </div>
  );
};

export default Locations;
